resource "aws_iam_role" "synthetic_role_059" {
  name = "synthetic_role_059"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_059_policy" {
  name   = "synthetic_role_059-policy"
  role   = aws_iam_role.synthetic_role_059.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "rds:CreateDBInstance"
            ],
            "Resource": "arn:aws:dynamodb:*:*:table/*"
        }
    ]
})
}
